import{_ as a,o as t,c as o,ag as r}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse(`{"title":"Welcome to Prova","description":"Verifiable storage for humanity's most important digital memory.","frontmatter":{"description":"Verifiable storage for humanity's most important digital memory."},"headers":[],"relativePath":"ABOUT.md","filePath":"ABOUT.md","lastUpdated":null}`),i={name:"ABOUT.md"};function s(n,e,l,p,d,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="welcome-to-prova" tabindex="-1">Welcome to Prova <a class="header-anchor" href="#welcome-to-prova" aria-label="Permalink to &quot;Welcome to Prova&quot;">​</a></h1><p>Prova is verifiable storage anchored to Ethereum.</p><p>You give Prova a file. Prova chunks it, replicates it across independent <strong>provers</strong>, and pins it down with an on-chain deal. Every day, every prover proves the file is still there with a cryptographic proof of data possession. You retrieve it over HTTPS, IPFS, or libp2p. You pay in USDC on Base. If a prover misses a proof, they get slashed and your file is re-pinned to a healthy prover.</p><p>That&#39;s the whole loop.</p><h2 id="three-things-people-store-on-prova-today" tabindex="-1">Three things people store on Prova today <a class="header-anchor" href="#three-things-people-store-on-prova-today" aria-label="Permalink to &quot;Three things people store on Prova today&quot;">​</a></h2><ul><li><strong>Static websites.</strong> Drop a build folder in, point your ENS contenthash at the returned <code>piece-cid</code>. Your site lives across the network, served over HTTPS, proven daily.</li><li><strong>Datasets.</strong> Upload a Parquet shard, a CSV, a research archive. Prova handles chunking, redundancy, and proof. Pay per TiB-month.</li><li><strong>AI corpora.</strong> Anchor model weights and training data so the corpus is auditable. Anyone can verify the file you trained on is the file you said.</li></ul><h2 id="three-ways-to-use-it" tabindex="-1">Three ways to use it <a class="header-anchor" href="#three-ways-to-use-it" aria-label="Permalink to &quot;Three ways to use it&quot;">​</a></h2><ul><li><a href="./getting-started/web-upload"><strong>Web upload</strong></a> — drag and drop in your browser, no install, no wallet. The fastest way to try Prova.</li><li><a href="./getting-started/cli"><strong>CLI</strong></a> — <code>prova put ./dist</code>, get a <code>piece-cid</code> back. One line.</li><li><a href="./api/"><strong>HTTP API</strong></a> — same endpoints from any language, any runtime.</li></ul><p>For programmatic / on-chain workflows, the <a href="./sdk/">TypeScript SDK</a> gives you a typed surface.</p><h2 id="what-s-different-about-prova" tabindex="-1">What&#39;s different about Prova <a class="header-anchor" href="#what-s-different-about-prova" aria-label="Permalink to &quot;What&#39;s different about Prova&quot;">​</a></h2><p>Prova is intentionally minimal. We are <strong>not</strong> building:</p><ul><li>a new chain</li><li>a token launch (no ICO, no airdrop)</li><li>sealed PoRep / TEE / fancy crypto theater</li><li>a custodial backup service</li></ul><p>Prova is <strong>PDP on Base</strong>, plus an ETH/USDC payment rail. Clients store. Provers stake. Ethereum settles. That&#39;s it.</p><p>If you want the full architecture, start at <a href="./concepts/architecture">How Prova works</a>. If you want to use it, <a href="./getting-started/web-upload">start storing</a>.</p>',14)])])}const f=a(i,[["render",s]]);export{u as __pageData,f as default};
